// Pull results from each upstream node
const newJobsData = $('New Jobs Count').first().json;
const appsData = $('Applications Count').first().json;
const topMatchesData = $('Top Matches').all().map(item => item.json);
const statusData = $('App Status Breakdown').all().map(item => item.json);

// Build status breakdown object
const statusBreakdown = {};
statusData.forEach(row => {
  statusBreakdown[row.status] = parseInt(row.count, 10);
});

// Build top matches array
const topMatches = topMatchesData.map(row => ({
  company: row.company_name,
  role: row.role_title,
  score: row.skill_match_score,
  applyLink: row.apply_link
}));

const summary = {
  date: new Date().toISOString().split('T')[0],
  newJobs: parseInt(newJobsData.new_jobs || 0, 10),
  appsMade: parseInt(appsData.apps_made || 0, 10),
  topMatches,
  statusBreakdown,
  totalApplications: Object.values(statusBreakdown).reduce((a, b) => a + b, 0)
};

return [{ json: summary }];
